checker_dsl:
EXISTS (`class C`) {
  AND {
    (`class C has java.lang.Iterable as a direct or indirect supertype`),
    EXISTS (`method M`) {
      AND {
        (`method M is declared in class C`),
        (`method M has name "iterator"`),
        EXISTS (`block B`) {
          AND {
            (`block B is the body of method M`),
            (`block B contains exactly one statement`),
            EXISTS (`return statement R`) {
              AND {
                (`statement R is the single statement in block B`),
                (`statement R is a return statement`),
                EXISTS (`expression E`) {
                  AND {
                    (`expression E is the returned expression in return statement R`),
                    (`expression E is a "this" access referring to class C instance`)
                  }
                }
              }
            }
          }
        }
      }
    },
    NOT {
      EXISTS (`method H`) {
        AND {
          (`method H is declared in class C`),
          (`method H has name "hasNext"`),
          EXISTS (`block BH`) {
            AND {
              (`block BH is the body of method H`),
              (`block BH contains exactly one statement`),
              EXISTS (`return statement RH`) {
                AND {
                  (`return statement RH is the single statement in block BH`),
                  (`return statement RH is a return statement`),
                  EXISTS (`boolean literal BL`) {
                    AND {
                      (`boolean literal BL is the returned expression in return statement RH`),
                      (`boolean literal BL has value false`)
                    }
                  }
                }
              }
            }
          }
        }
      }
    }
  }
}
